import React, { useMemo, useState, useEffect } from 'react';
import './StubPages.css';

const Billing = () => {
  const [formData, setFormData] = useState({
    patientName: '',
    consultationFee: '',
    medicineFee: '',
    labFee: '',
    paymentMethod: 'UPI',
    paymentStatus: 'Pending',
  });

  // ✅ Persistent storage
  const [bills, setBills] = useState(() => {
    const saved = localStorage.getItem('bills');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('bills', JSON.stringify(bills));
  }, [bills]);

  // ✅ Auto total calculation
  const totalAmount = useMemo(() => {
    const consultation = Number(formData.consultationFee) || 0;
    const medicine = Number(formData.medicineFee) || 0;
    const lab = Number(formData.labFee) || 0;
    return consultation + medicine + lab;
  }, [formData]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  // ✅ Save Bill
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.patientName) {
      alert('Please enter patient name');
      return;
    }

    const newBill = {
      id: Date.now(),
      ...formData,
      totalAmount,
    };

    setBills((prev) => [newBill, ...prev]);

    setFormData({
      patientName: '',
      consultationFee: '',
      medicineFee: '',
      labFee: '',
      paymentMethod: 'UPI',
      paymentStatus: 'Pending',
    });
  };

  // ✅ PRINT FUNCTION (FIXED)
  const handlePrint = (bill) => {
    const printWindow = window.open('', '', 'width=600,height=600');

    printWindow.document.write(`
      <html>
        <head>
          <title>Hospital Bill</title>
          <style>
            body { font-family: Arial; padding: 20px; }
            h2 { text-align: center; }
            table { width: 100%; margin-top: 20px; border-collapse: collapse; }
            td, th { border: 1px solid #ddd; padding: 10px; }
          </style>
        </head>
        <body>
          <h2>🏥 Hospital Bill</h2>

          <p><strong>Patient:</strong> ${bill.patientName}</p>
          <p><strong>Date:</strong> ${new Date().toLocaleDateString()}</p>

          <table>
            <tr><th>Consultation</th><td>₹${bill.consultationFee}</td></tr>
            <tr><th>Medicine</th><td>₹${bill.medicineFee}</td></tr>
            <tr><th>Lab</th><td>₹${bill.labFee}</td></tr>
            <tr><th>Total</th><td><strong>₹${bill.totalAmount}</strong></td></tr>
            <tr><th>Payment Method</th><td>${bill.paymentMethod}</td></tr>
            <tr><th>Status</th><td>${bill.paymentStatus}</td></tr>
          </table>

          <br/>
          <p style="text-align:center;">Thank you for visiting our hospital!</p>
        </body>
      </html>
    `);

    printWindow.document.close();
    printWindow.print();
  };

  return (
    <div className="page">
      <h2>Billing</h2>
      <p>Create bills manually and manage payment details</p>

      <div className="billing-grid">
        {/* FORM */}
        <div className="table-card">
          <h3>Create New Bill</h3>

          <form onSubmit={handleSubmit} className="billing-form">
            <input
              type="text"
              name="patientName"
              placeholder="Patient Name"
              value={formData.patientName}
              onChange={handleChange}
              required
            />

            <input
              type="number"
              name="consultationFee"
              placeholder="Consultation Fee"
              value={formData.consultationFee}
              onChange={handleChange}
            />

            <input
              type="number"
              name="medicineFee"
              placeholder="Medicine Fee"
              value={formData.medicineFee}
              onChange={handleChange}
            />

            <input
              type="number"
              name="labFee"
              placeholder="Lab Fee"
              value={formData.labFee}
              onChange={handleChange}
            />

            <select name="paymentMethod" value={formData.paymentMethod} onChange={handleChange}>
              <option value="UPI">UPI</option>
              <option value="Card">Card</option>
              <option value="Cash">Cash</option>
            </select>

            <select name="paymentStatus" value={formData.paymentStatus} onChange={handleChange}>
              <option value="Pending">Pending</option>
              <option value="Paid">Paid</option>
            </select>

            <div className="amount-box">
              <strong>Total Amount: ₹{totalAmount}</strong>
            </div>

            {/* UPI QR */}
            {formData.paymentMethod === 'UPI' && (
              <div className="payment-box">
                <h4>Scan QR to Pay</h4>
                <img
                  src={`https://api.qrserver.com/v1/create-qr-code/?size=180x180&data=upi://pay?pa=demo@upi&pn=HospitalHub&am=${totalAmount}&cu=INR`}
                  alt="QR"
                  className="qr-image"
                />
                <p>UPI ID: demo@upi</p>
              </div>
            )}

            <button type="submit" className="action-btn">
              Save Bill
            </button>
          </form>
        </div>

        {/* TABLE */}
        <div className="table-card">
          <h3>Billing Records</h3>

          {bills.length === 0 ? (
            <p>No billing records yet.</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Patient</th>
                  <th>Total</th>
                  <th>Method</th>
                  <th>Status</th>
                  <th>Print</th>
                </tr>
              </thead>

              <tbody>
                {bills.map((bill) => (
                  <tr key={bill.id}>
                    <td>{bill.patientName}</td>
                    <td>₹{bill.totalAmount}</td>
                    <td>{bill.paymentMethod}</td>
                    <td>{bill.paymentStatus}</td>
                    <td>
                      <button onClick={() => handlePrint(bill)}>🖨 Print</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default Billing;
